const msg = $json.message || {};
const chat = msg.chat || {};
const from = msg.from || {};
const text = (msg.text || msg.caption || "").trim();

let route = "verify";
if (!text) route = "invalid";
else if (text.startsWith("/start")) route = "start";
else if (text.startsWith("/help")) route = "help";
else if (text.startsWith("/about")) route = "about";

return [{
  json: {
    route,
    chat_id: chat.id,
    message_id: msg.message_id,
    text,
    username: from.username || "",
    first_name: from.first_name || "",
    last_name: from.last_name || "",
    chat_type: chat.type || "private",
    raw: $json
  }
}];

function sleep(ms) { return new Promise(resolve => setTimeout(resolve, ms)); }
function htmlEscape(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\"/g, "&quot;")
    .replace(/'/g, "&#39;");
}
function pick(obj, paths) {
  for (const path of paths) {
    const parts = path.split(".");
    let cur = obj;
    for (const part of parts) cur = cur?.[part];
    if (cur !== undefined && cur !== null && cur !== "") return cur;
  }
  return null;
}
function normalizeConfidence(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) return null;
  return num <= 1 ? Math.round(num * 100) : Math.round(num);
}
const input = $input.first().json;
const backendUrl = ($env.JACHAI_BACKEND_URL || "https://your-backend-domain.com").replace(/\/$/, "");
const internalKey = $env.JACHAI_INTERNAL_API_KEY || "";
if (!internalKey) {
  return [{ json: { chat_id: input.chat_id, telegram_text: "⚠️ <b>JachAI internal API key is missing in n8n.</b>\n\nSet <code>JACHAI_INTERNAL_API_KEY</code> in your n8n environment before using this workflow." } }];
}
const submitPayload = {
  platform: "telegram",
  sender_id: String(input.chat_id),
  message_id: String(input.message_id || ""),
  text: input.text,
  metadata: {
    username: input.username || "",
    first_name: input.first_name || "",
    last_name: input.last_name || "",
    chat_type: input.chat_type || "private"
  }
};
let submitResponse;
try {
  submitResponse = await fetch(`${backendUrl}/api/v1/webhooks/inbound-message`, {
    method: "POST",
    headers: { "Content-Type": "application/json", "X-Internal-API-Key": internalKey },
    body: JSON.stringify(submitPayload)
  });
} catch (error) {
  return [{ json: { chat_id: input.chat_id, telegram_text: `⚠️ <b>JachAI backend is unreachable.</b>\n\n${htmlEscape(error.message)}` } }];
}
if (!submitResponse.ok) {
  const errText = await submitResponse.text();
  return [{ json: { chat_id: input.chat_id, telegram_text: `⚠️ <b>JachAI could not start verification.</b>\n\nHTTP ${submitResponse.status}\n${htmlEscape(errText.slice(0, 800))}` } }];
}
const submitData = await submitResponse.json();
let jobId = pick(submitData, ["job.id", "job_id", "data.job.id", "data.job_id"]);
let claimId = pick(submitData, ["claim.id", "job.claim_id", "claim_id", "data.claim.id", "data.job.claim_id"]);
let claim = submitData.claim || submitData.data?.claim || null;
let status = String(pick(submitData, ["job.status", "status", "data.job.status"]) || "").toLowerCase();
if (claim?.id && !claimId) claimId = claim.id;
if (!jobId && !claimId) {
  return [{ json: { chat_id: input.chat_id, telegram_text: "⚠️ <b>JachAI started but did not return a job ID or claim ID.</b>\n\nPlease check the inbound webhook response shape." } }];
}
let lastError = null;
const maxAttempts = Number($env.JACHAI_TELEGRAM_MAX_POLL_ATTEMPTS || 75);
const delayMs = Number($env.JACHAI_TELEGRAM_POLL_DELAY_MS || 5000);
for (let attempt = 1; attempt <= maxAttempts; attempt++) {
  if (!jobId || claimId || claim) break;
  await sleep(delayMs);
  try {
    const jobResponse = await fetch(`${backendUrl}/api/v1/verification-jobs/${jobId}`, {
      method: "GET",
      headers: { "X-Internal-API-Key": internalKey }
    });
    if (!jobResponse.ok) {
      lastError = `Job poll HTTP ${jobResponse.status}`;
      continue;
    }
    const jobData = await jobResponse.json();
    status = String(pick(jobData, ["status", "job.status", "data.status"]) || "").toLowerCase();
    claimId = pick(jobData, ["claim_id", "job.claim_id", "data.claim_id", "result.claim_id"]) || claimId;
    if (["failed", "error", "cancelled", "canceled"].includes(status)) {
      const reason = pick(jobData, ["error_message", "message", "job.error_message", "data.error_message"]) || "Verification failed.";
      return [{ json: { chat_id: input.chat_id, telegram_text: `❌ <b>JachAI verification failed.</b>\n\n${htmlEscape(reason)}` } }];
    }
  } catch (error) {
    lastError = error.message;
  }
}
if (!claim && claimId) {
  let claimResponse;
  try {
    claimResponse = await fetch(`${backendUrl}/api/v1/claims/${claimId}`, {
      method: "GET",
      headers: { "X-Internal-API-Key": internalKey }
    });
  } catch (error) {
    return [{ json: { chat_id: input.chat_id, telegram_text: `⚠️ <b>Could not fetch final claim result.</b>\n\n${htmlEscape(error.message)}` } }];
  }
  if (!claimResponse.ok) {
    const errText = await claimResponse.text();
    return [{ json: { chat_id: input.chat_id, telegram_text: `⚠️ <b>Could not fetch final claim result.</b>\n\nHTTP ${claimResponse.status}\n${htmlEscape(errText.slice(0, 800))}` } }];
  }
  const claimPayload = await claimResponse.json();
  claim = claimPayload.claim || claimPayload.data?.claim || claimPayload;
}
if (!claim) {
  return [{ json: { chat_id: input.chat_id, telegram_text: `⏳ <b>JachAI is still processing this claim.</b>\n\nPlease try again shortly.${lastError ? `\n\nDebug: ${htmlEscape(lastError)}` : ""}` } }];
}
const verdict = claim.verdict || claim.final_verdict || "Unknown";
const confidencePercent = normalizeConfidence(claim.confidence ?? claim.confidence_score ?? null);
const confidenceLabel = claim.confidence_label || "";
const extractedClaim = claim.extracted_claim || claim.cleaned_text || claim.raw_text || input.text;
const summary = claim.user_response || claim.share_summary || claim.explanation || "No summary available.";
const explanation = claim.explanation || "";
const emojiMap = {
  "Likely True": "✅",
  "Likely False": "❌",
  "Misleading": "⚠️",
  "Not Enough Evidence": "❓"
};
const emoji = emojiMap[verdict] || "🧠";
const evidence = (claim.evidence || claim.sources || claim.evidence_sources || []).slice(0, 3);
const sources = evidence.map((source, index) => {
  const title = htmlEscape(source.title || source.publisher || `Source ${index + 1}`);
  const url = htmlEscape(source.url || "");
  return url ? `${index + 1}. <a href="${url}">${title}</a>` : `${index + 1}. ${title}`;
}).join("\n");
const confidenceText = confidencePercent !== null
  ? `${htmlEscape(confidenceLabel || "Confidence")} (${confidencePercent}%)`
  : htmlEscape(confidenceLabel || "Unknown");
let text = `${emoji} <b>JachAI Verdict:</b> ${htmlEscape(verdict)}\n\n`;
text += `<b>Confidence:</b> ${confidenceText}\n\n`;
text += `<b>Claim checked:</b>\n${htmlEscape(extractedClaim).slice(0, 700)}\n\n`;
text += `<b>Summary:</b>\n${htmlEscape(summary).slice(0, 1000)}\n\n`;
if (explanation && explanation !== summary) {
  text += `<b>Why:</b>\n${htmlEscape(explanation).slice(0, 700)}\n\n`;
}
text += `<b>Sources:</b>\n${sources || "No strong public sources found."}\n\n`;
text += `<i>Job ID:</i> <code>${htmlEscape(String(jobId || "n/a"))}</code>`;
return [{ json: { chat_id: input.chat_id, claim_id: claim.id || claimId, job_id: jobId, telegram_text: text } }];
